UPDATE SWC_USER
SET USER_NM        = #{name, jdbcType=VARCHAR}
  , USER_PASSWORD  = #{password, jdbcType=VARCHAR}
  , USER_IMAGE_URI = #{imageUrl, jdbcType=VARCHAR}
  , USER_SEXDSTN   = #{sex, jdbcType=VARCHAR}
  , USER_EMAIL     = #{email, jdbcType=VARCHAR}
  , USER_DC        = #{remarks, jdbcType=VARCHAR}
  , USER_USE       = UPPER(#{use, jdbcType=VARCHAR})
  , USER_LOCK      = UPPER(#{lock, jdbcType=VARCHAR})
  , HIST_ID        = NULL
  , UPDT_DT        = NOW()
  , UPDT_ID        = #{updateId, jdbcType=VARCHAR}
  , USER_MBTLNUM   = #{mobile, jdbcType=VARCHAR}
WHERE USER_ID = UPPER(#{id, jdbcType=VARCHAR})
